import{_ as e,o as a,c as r,ag as o}from"./chunks/framework.OsDJF_Ea.js";const s="/docs/modules/spectral-capture.png",g=JSON.parse('{"title":"Spectral Capture","description":"","frontmatter":{},"headers":[],"relativePath":"modules/spectral-capture.md","filePath":"modules/spectral-capture.md"}'),n={name:"modules/spectral-capture.md"};function d(i,t,p,l,u,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="spectral-capture" tabindex="-1">Spectral Capture <a class="header-anchor" href="#spectral-capture" aria-label="Permalink to &quot;Spectral Capture&quot;">​</a></h1><p><strong>Category:</strong> Granular / Looping</p><p>Captures 2048 samples of audio on trigger, runs FFT, and extracts the 16 strongest spectral peaks (frequency, amplitude, Q). The result is stored as a global spectral profile that ModalResonator can load via its trigger input or Btn1. Uses parabolic interpolation for sub-bin frequency accuracy.</p><img src="'+s+'" alt="spectral-capture module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inL</strong> (audio)</td><td>Audio input to analyze (piezo, contact mic, any audio source).</td></tr><tr><td><strong>arm</strong></td><td>Rising edge arms the capture (record-arm mode). When armed, the next trigger starts capture, then auto-disarms. Connect a button or MIDI note.</td></tr><tr><td><strong>trigger</strong></td><td>Rising edge starts capture (only when armed). After 2048 samples (~46ms at 44.1kHz), FFT runs and peaks are extracted.</td></tr><tr><td><strong>threshold</strong></td><td>Noise floor threshold multiplier (0-1 mapped to 0.5x-10x). Higher = fewer peaks detected, only strongest survive.</td></tr><tr><td><strong>gain</strong></td><td>Input gain before capture (0-1 mapped to 0-4x).</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Audio pass-through (with gain applied).</td></tr><tr><td><strong>analysis_done</strong></td><td>Outputs 1.0 for one block when FFT analysis completes, 0.0 otherwise. Connect to ModalResonator trigger to auto-load the captured profile.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Patch: Button/MIDI -&gt; arm, PiezoInput trigger -&gt; trigger, PiezoInput audio -&gt; inL, analysis_done -&gt; ModalResonator trigger. Press arm button, tap an object, its resonances are captured and loaded into the resonator. Module stays idle until re-armed.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const m=e(n,[["render",d]]);export{g as __pageData,m as default};
